mcp:tool-listener.mcp:parameters-schema:
{
    "$schema": "# SECURITY: Remote schema removed (http://json-schema.org/draft-07/schema#)",
    "type": "object",
    "properties":
    {
        "objectname":
        {
            "type": "string",
            "description": "The Salesforce SObject API name of the record to create. Examples: Lead, Contact, Account, Opportunity, Case. Case-sensitive."
        },
        "fields":
        {
            "type": "object",
            "description": "A JSON object of Salesforce field API names and their values to set on the new record. Example: {\"FirstName\": \"John\", \"LastName\": \"Smith\", \"Company\": \"Acme Corp\", \"Email\": \"john@acme.com\"}"
        }
    },
    "required":
    [
        "objectname",
        "fields"
    ]
}

{
    "$schema": "# SECURITY: Remote schema removed (http://json-schema.org/draft-07/schema#)",
    "type": "object",
    "properties":
    {
        "soql":
        {
            "type": "string",
            "description": "A valid SOQL (Salesforce Object Query Language) query string. Must start with SELECT and include FROM clause. Example: SELECT Id, Name, Email FROM Lead WHERE Company = 'Acme Corp' LIMIT 50"
        }
    },
    "required":
    [
        "soql"
    ]
}

{
                "$schema": "# SECURITY: Remote schema removed (http://json-schema.org/draft-07/schema#)",
                "type": "object",
                "properties": {
                    "objectname": {
                        "type": "string",
                        "description": "The Salesforce SObject API name of the record to update. Examples: Lead, Contact, Account, Opportunity, Case."
                    },
                    "fields": {
                        "type": "object",
                        "description": "A JSON object containing the Salesforce record 'Id' field (required) plus all fields to update. Example: {\"Id\": \"00Q000000000001AAA\", \"Status\": \"Working\", \"StageName\": \"Closed Won\"}"
                    }
                },
                "required": ["objectname", "fields"]
            }

{
    "$schema": "# SECURITY: Remote schema removed (http://json-schema.org/draft-07/schema#)",
    "type": "object",
    "properties":
    {
        "objectname":
        {
            "type": "string",
            "description": "The Salesforce SObject API name. Examples: Lead, Contact, Account, Opportunity."
        },
        "externalidfieldname":
        {
            "type": "string",
            "description": "The API name of the external ID field on the SObject used to match the record. Example: External_ID__c or CRM_ID__c. This field must be marked as External ID in Salesforce."
        },
        "fields":
        {
            "type": "object",
            "description": "A JSON object containing the external ID field value (for matching) plus all fields to create or update. Example: {\"External_ID__c\": \"EXT-001\", \"LastName\": \"Smith\", \"Company\": \"Acme Corp\", \"Email\": \"smith@acme.com\"}"
        }
    },
    "required":
    [
        "objectname",
        "externalidfieldname",
        "fields"
    ]
}
